	localparam WIDTH = 8;
	localparam FRAC = 16;

	typedef struct packed {
		cv_pkt_pkg::pkt_rgb in;

		logic [WIDTH - 1: 0] cmax;
		logic [WIDTH - 1: 0] cmin;
		logic [WIDTH - 1: 0] delta;

		logic [FRAC: 0] inv_delta;
		logic [FRAC: 0] inv_cmax;

		logic [WIDTH + FRAC - 1: 0] temp_h;
		logic [WIDTH + FRAC - 1: 0] temp_s;

		logic tlast;
		logic tvalid;
		logic tready;
	} pipe_stage;

	logic [FRAC: 0] inv_rom_cmax[0: 2 ** WIDTH - 1] = { 'b00000000000000000, 'b10000000000000000, 'b01000000000000000, 'b00101010101010101, 'b00100000000000000, 'b00011001100110011, 'b00010101010101011, 'b00010010010010010, 'b00010000000000000, 'b00001110001110010, 'b00001100110011010, 'b00001011101000110, 'b00001010101010101, 'b00001001110110001, 'b00001001001001001, 'b00001000100010001, 'b00001000000000000, 'b00000111100001111, 'b00000111000111001, 'b00000110101111001, 'b00000110011001101, 'b00000110000110001, 'b00000101110100011, 'b00000101100100001, 'b00000101010101011, 'b00000101000111101, 'b00000100111011001, 'b00000100101111011, 'b00000100100100101, 'b00000100011010100, 'b00000100010001001, 'b00000100001000010, 'b00000100000000000, 'b00000011111000010, 'b00000011110001000, 'b00000011101010000, 'b00000011100011100, 'b00000011011101011, 'b00000011010111101, 'b00000011010010000, 'b00000011001100110, 'b00000011000111110, 'b00000011000011000, 'b00000010111110100, 'b00000010111010001, 'b00000010110110000, 'b00000010110010001, 'b00000010101110010, 'b00000010101010101, 'b00000010100111001, 'b00000010100011111, 'b00000010100000101, 'b00000010011101100, 'b00000010011010101, 'b00000010010111110, 'b00000010010101000, 'b00000010010010010, 'b00000010001111110, 'b00000010001101010, 'b00000010001010111, 'b00000010001000100, 'b00000010000110010, 'b00000010000100001, 'b00000010000010000, 'b00000010000000000, 'b00000001111110000, 'b00000001111100001, 'b00000001111010010, 'b00000001111000100, 'b00000001110110110, 'b00000001110101000, 'b00000001110011011, 'b00000001110001110, 'b00000001110000010, 'b00000001101110110, 'b00000001101101010, 'b00000001101011110, 'b00000001101010011, 'b00000001101001000, 'b00000001100111110, 'b00000001100110011, 'b00000001100101001, 'b00000001100011111, 'b00000001100010110, 'b00000001100001100, 'b00000001100000011, 'b00000001011111010, 'b00000001011110001, 'b00000001011101001, 'b00000001011100000, 'b00000001011011000, 'b00000001011010000, 'b00000001011001000, 'b00000001011000001, 'b00000001010111001, 'b00000001010110010, 'b00000001010101011, 'b00000001010100100, 'b00000001010011101, 'b00000001010010110, 'b00000001010001111, 'b00000001010001001, 'b00000001010000011, 'b00000001001111100, 'b00000001001110110, 'b00000001001110000, 'b00000001001101010, 'b00000001001100100, 'b00000001001011111, 'b00000001001011001, 'b00000001001010100, 'b00000001001001110, 'b00000001001001001, 'b00000001001000100, 'b00000001000111111, 'b00000001000111010, 'b00000001000110101, 'b00000001000110000, 'b00000001000101011, 'b00000001000100111, 'b00000001000100010, 'b00000001000011110, 'b00000001000011001, 'b00000001000010101, 'b00000001000010001, 'b00000001000001100, 'b00000001000001000, 'b00000001000000100, 'b00000001000000000, 'b00000000111111100, 'b00000000111111000, 'b00000000111110100, 'b00000000111110000, 'b00000000111101101, 'b00000000111101001, 'b00000000111100101, 'b00000000111100010, 'b00000000111011110, 'b00000000111011011, 'b00000000111010111, 'b00000000111010100, 'b00000000111010001, 'b00000000111001110, 'b00000000111001010, 'b00000000111000111, 'b00000000111000100, 'b00000000111000001, 'b00000000110111110, 'b00000000110111011, 'b00000000110111000, 'b00000000110110101, 'b00000000110110010, 'b00000000110101111, 'b00000000110101100, 'b00000000110101010, 'b00000000110100111, 'b00000000110100100, 'b00000000110100001, 'b00000000110011111, 'b00000000110011100, 'b00000000110011010, 'b00000000110010111, 'b00000000110010101, 'b00000000110010010, 'b00000000110010000, 'b00000000110001101, 'b00000000110001011, 'b00000000110001000, 'b00000000110000110, 'b00000000110000100, 'b00000000110000010, 'b00000000101111111, 'b00000000101111101, 'b00000000101111011, 'b00000000101111001, 'b00000000101110110, 'b00000000101110100, 'b00000000101110010, 'b00000000101110000, 'b00000000101101110, 'b00000000101101100, 'b00000000101101010, 'b00000000101101000, 'b00000000101100110, 'b00000000101100100, 'b00000000101100010, 'b00000000101100000, 'b00000000101011110, 'b00000000101011101, 'b00000000101011011, 'b00000000101011001, 'b00000000101010111, 'b00000000101010101, 'b00000000101010100, 'b00000000101010010, 'b00000000101010000, 'b00000000101001110, 'b00000000101001101, 'b00000000101001011, 'b00000000101001001, 'b00000000101001000, 'b00000000101000110, 'b00000000101000100, 'b00000000101000011, 'b00000000101000001, 'b00000000101000000, 'b00000000100111110, 'b00000000100111101, 'b00000000100111011, 'b00000000100111010, 'b00000000100111000, 'b00000000100110111, 'b00000000100110101, 'b00000000100110100, 'b00000000100110010, 'b00000000100110001, 'b00000000100101111, 'b00000000100101110, 'b00000000100101101, 'b00000000100101011, 'b00000000100101010, 'b00000000100101001, 'b00000000100100111, 'b00000000100100110, 'b00000000100100101, 'b00000000100100011, 'b00000000100100010, 'b00000000100100001, 'b00000000100011111, 'b00000000100011110, 'b00000000100011101, 'b00000000100011100, 'b00000000100011010, 'b00000000100011001, 'b00000000100011000, 'b00000000100010111, 'b00000000100010110, 'b00000000100010101, 'b00000000100010011, 'b00000000100010010, 'b00000000100010001, 'b00000000100010000, 'b00000000100001111, 'b00000000100001110, 'b00000000100001101, 'b00000000100001011, 'b00000000100001010, 'b00000000100001001, 'b00000000100001000, 'b00000000100000111, 'b00000000100000110, 'b00000000100000101, 'b00000000100000100, 'b00000000100000011, 'b00000000100000010, 'b00000000100000001 };
	logic [FRAC: 0] inv_rom_delta[0: 2 ** WIDTH - 1] = { 'b00000000000000000, 'b10000000000000000, 'b01000000000000000, 'b00101010101010101, 'b00100000000000000, 'b00011001100110011, 'b00010101010101011, 'b00010010010010010, 'b00010000000000000, 'b00001110001110010, 'b00001100110011010, 'b00001011101000110, 'b00001010101010101, 'b00001001110110001, 'b00001001001001001, 'b00001000100010001, 'b00001000000000000, 'b00000111100001111, 'b00000111000111001, 'b00000110101111001, 'b00000110011001101, 'b00000110000110001, 'b00000101110100011, 'b00000101100100001, 'b00000101010101011, 'b00000101000111101, 'b00000100111011001, 'b00000100101111011, 'b00000100100100101, 'b00000100011010100, 'b00000100010001001, 'b00000100001000010, 'b00000100000000000, 'b00000011111000010, 'b00000011110001000, 'b00000011101010000, 'b00000011100011100, 'b00000011011101011, 'b00000011010111101, 'b00000011010010000, 'b00000011001100110, 'b00000011000111110, 'b00000011000011000, 'b00000010111110100, 'b00000010111010001, 'b00000010110110000, 'b00000010110010001, 'b00000010101110010, 'b00000010101010101, 'b00000010100111001, 'b00000010100011111, 'b00000010100000101, 'b00000010011101100, 'b00000010011010101, 'b00000010010111110, 'b00000010010101000, 'b00000010010010010, 'b00000010001111110, 'b00000010001101010, 'b00000010001010111, 'b00000010001000100, 'b00000010000110010, 'b00000010000100001, 'b00000010000010000, 'b00000010000000000, 'b00000001111110000, 'b00000001111100001, 'b00000001111010010, 'b00000001111000100, 'b00000001110110110, 'b00000001110101000, 'b00000001110011011, 'b00000001110001110, 'b00000001110000010, 'b00000001101110110, 'b00000001101101010, 'b00000001101011110, 'b00000001101010011, 'b00000001101001000, 'b00000001100111110, 'b00000001100110011, 'b00000001100101001, 'b00000001100011111, 'b00000001100010110, 'b00000001100001100, 'b00000001100000011, 'b00000001011111010, 'b00000001011110001, 'b00000001011101001, 'b00000001011100000, 'b00000001011011000, 'b00000001011010000, 'b00000001011001000, 'b00000001011000001, 'b00000001010111001, 'b00000001010110010, 'b00000001010101011, 'b00000001010100100, 'b00000001010011101, 'b00000001010010110, 'b00000001010001111, 'b00000001010001001, 'b00000001010000011, 'b00000001001111100, 'b00000001001110110, 'b00000001001110000, 'b00000001001101010, 'b00000001001100100, 'b00000001001011111, 'b00000001001011001, 'b00000001001010100, 'b00000001001001110, 'b00000001001001001, 'b00000001001000100, 'b00000001000111111, 'b00000001000111010, 'b00000001000110101, 'b00000001000110000, 'b00000001000101011, 'b00000001000100111, 'b00000001000100010, 'b00000001000011110, 'b00000001000011001, 'b00000001000010101, 'b00000001000010001, 'b00000001000001100, 'b00000001000001000, 'b00000001000000100, 'b00000001000000000, 'b00000000111111100, 'b00000000111111000, 'b00000000111110100, 'b00000000111110000, 'b00000000111101101, 'b00000000111101001, 'b00000000111100101, 'b00000000111100010, 'b00000000111011110, 'b00000000111011011, 'b00000000111010111, 'b00000000111010100, 'b00000000111010001, 'b00000000111001110, 'b00000000111001010, 'b00000000111000111, 'b00000000111000100, 'b00000000111000001, 'b00000000110111110, 'b00000000110111011, 'b00000000110111000, 'b00000000110110101, 'b00000000110110010, 'b00000000110101111, 'b00000000110101100, 'b00000000110101010, 'b00000000110100111, 'b00000000110100100, 'b00000000110100001, 'b00000000110011111, 'b00000000110011100, 'b00000000110011010, 'b00000000110010111, 'b00000000110010101, 'b00000000110010010, 'b00000000110010000, 'b00000000110001101, 'b00000000110001011, 'b00000000110001000, 'b00000000110000110, 'b00000000110000100, 'b00000000110000010, 'b00000000101111111, 'b00000000101111101, 'b00000000101111011, 'b00000000101111001, 'b00000000101110110, 'b00000000101110100, 'b00000000101110010, 'b00000000101110000, 'b00000000101101110, 'b00000000101101100, 'b00000000101101010, 'b00000000101101000, 'b00000000101100110, 'b00000000101100100, 'b00000000101100010, 'b00000000101100000, 'b00000000101011110, 'b00000000101011101, 'b00000000101011011, 'b00000000101011001, 'b00000000101010111, 'b00000000101010101, 'b00000000101010100, 'b00000000101010010, 'b00000000101010000, 'b00000000101001110, 'b00000000101001101, 'b00000000101001011, 'b00000000101001001, 'b00000000101001000, 'b00000000101000110, 'b00000000101000100, 'b00000000101000011, 'b00000000101000001, 'b00000000101000000, 'b00000000100111110, 'b00000000100111101, 'b00000000100111011, 'b00000000100111010, 'b00000000100111000, 'b00000000100110111, 'b00000000100110101, 'b00000000100110100, 'b00000000100110010, 'b00000000100110001, 'b00000000100101111, 'b00000000100101110, 'b00000000100101101, 'b00000000100101011, 'b00000000100101010, 'b00000000100101001, 'b00000000100100111, 'b00000000100100110, 'b00000000100100101, 'b00000000100100011, 'b00000000100100010, 'b00000000100100001, 'b00000000100011111, 'b00000000100011110, 'b00000000100011101, 'b00000000100011100, 'b00000000100011010, 'b00000000100011001, 'b00000000100011000, 'b00000000100010111, 'b00000000100010110, 'b00000000100010101, 'b00000000100010011, 'b00000000100010010, 'b00000000100010001, 'b00000000100010000, 'b00000000100001111, 'b00000000100001110, 'b00000000100001101, 'b00000000100001011, 'b00000000100001010, 'b00000000100001001, 'b00000000100001000, 'b00000000100000111, 'b00000000100000110, 'b00000000100000101, 'b00000000100000100, 'b00000000100000011, 'b00000000100000010, 'b00000000100000001 };

	pipe_stage s0;
	pipe_stage s1;
	pipe_stage s2;
	pipe_stage s3;
	pipe_stage s4;

	always_ff @(posedge aclk or negedge aresetn) begin
		if (aresetn == 0) begin
			s0.tvalid <= '0;
			s0.tlast <= '0;
			s0.in <= '0;
			s0.cmax <= '0;
			s0.cmin <= '0;
			s1.tvalid <= '0;
			s1.tlast <= '0;
			s1.in <= '0;
			s1.cmax <= '0;
			s1.delta <= '0;
			s1.inv_cmax <= '0;
			s2.tvalid <= '0;
			s2.tlast <= '0;
			s2.in <= '0;
			s2.cmax <= '0;
			s2.temp_s <= '0;
			s2.inv_delta <= '0;
			s3.tvalid <= '0;
			s3.tlast <= '0;
			s3.cmax <= '0;
			s3.temp_s <= '0;
			s3.temp_h <= '0;
			s4.tvalid <= '0;
			s4.tlast <= '0;
			s4.cmax <= '0;
			s4.temp_s <= '0;
			s4.temp_h <= '0;

			m_tlast <= '0;
			m_tvalid <= '0;
			out <= '0;
		end else begin
			// pipe 0
			s0.tvalid <= s_tvalid;
			s0.tlast <= s_tlast;
			s0.in <= in;
			s0.cmax <= (in.r > in.g) ? ((in.r > in.b) ? in.r : in.b) : ((in.g > in.b) ? in.g : in.b);
			s0.cmin <= (in.r < in.g) ? ((in.r < in.b) ? in.r : in.b) : ((in.g < in.b) ? in.g : in.b);

			// pipe 1
			s1.tvalid <= s0.tvalid;
			s1.tlast <= s0.tlast;
			s1.in <= s0.in;
			s1.cmax <= s0.cmax;
			s1.delta <= s0.cmax - s0.cmin;
			s1.inv_cmax <= inv_rom_cmax[s0.cmax];

			// pipe 2
			s2.tvalid <= s1.tvalid;
			s2.tlast <= s1.tlast;
			s2.in <= s1.in;
			s2.cmax <= s1.cmax;
			s2.inv_delta <= inv_rom_delta[s1.delta];
			s2.temp_s <=
				(s1.delta != 0) ?
					((s1.delta != s1.cmax) ?
						(s1.delta * s1.inv_cmax) >> 8:
						255):
					0;

			// pipe 3
			s3.tvalid <= s2.tvalid;
			s3.tlast <= s2.tlast;
			s3.cmax <= s2.cmax;
			s3.temp_s <= s2.temp_s;
			case (s2.cmax)
				s2.in.r: begin
					s3.temp_h <= (s2.in.g - s2.in.b) * s2.inv_delta;
				end

				s2.in.g: begin
					s3.temp_h <= (s2.in.b - s2.in.r) * s2.inv_delta + (2 << FRAC);
				end

				s2.in.b: begin
					s3.temp_h <= (s2.in.r - s2.in.g) * s2.inv_delta + (4 << FRAC);
				end
			endcase

			// pipe 4
			s4.tvalid <= s3.tvalid;
			s4.tlast <= s3.tlast;
			s4.cmax <= s3.cmax;
			s4.temp_s <= s3.temp_s;
			s4.temp_h <= (s3.temp_h * 30) + (s3.temp_h[WIDTH + FRAC - 1] ? (180 << FRAC): 0);

			// pipe 5
			m_tvalid <= s4.tvalid;
			m_tlast <= s4.tlast;
			out.h <= s4.temp_h[WIDTH + FRAC - 1: FRAC];
			out.s <= s4.temp_s;
			out.v <= s4.cmax;
		end
	end

